mapper.select:
SELECT * FROM ( SELECT ROWNUM AS rnum, res.* FROM ( SELECT cr.room_id AS "room_id", LOWER(cr.room_type) AS "room_type", cr.festival_id AS "festival_id", cr.owner_id AS "owner_id", m.nickname AS "nickname", m.profile_image_url AS "profile_image_url", NVL(cr.room_title, fi.title || ' 공식 모임') AS "room_title", NVL(cr.room_description, fi.title || ' 공식 모임방입니다.') AS "room_description", NVL(cr.free_location, fi.addr1) AS "free_location", NVL(TO_CHAR(cr.free_date, 'YYYY.MM.DD'), SUBSTR(fi.event_start_date, 1, 4) || '.' || SUBSTR(fi.event_start_date, 5, 2) || '.' || SUBSTR(fi.event_start_date, 7, 2) || ' ~ ' || SUBSTR(fi.event_end_date, 1, 4) || '.' || SUBSTR(fi.event_end_date, 5, 2) || '.' || SUBSTR(fi.event_end_date, 7, 2)) AS "free_date", cr.max_capacity AS "max_capacity", NVL(cr.room_image, fi.first_image) AS "room_image", TO_CHAR(cru.joined_at, 'YYYY-MM-DD HH24:MI:SS') AS "joined_at", (SELECT COUNT(*) FROM chat_room_user sub_cru WHERE sub_cru.room_id = cr.room_id) AS "current_count" FROM chat_room cr JOIN chat_room_user cru ON cr.room_id = cru.room_id LEFT JOIN festival_info fi ON cr.festival_id = fi.content_id LEFT JOIN member m ON cr.owner_id = m.member_id WHERE cru.member_id = #{member_id} AND (cr.festival_id IS NULL OR fi.is_visible = 'Y') AND cr.room_type = 'FESTIVAL' AND cr.room_type = 'GROUP' AND cr.owner_id = #{member_id}
AND (cr.room_title LIKE '%' || #{keyword} || '%' OR (cr.room_title IS NULL AND fi.title LIKE '%' || #{keyword} || '%'))
ORDER BY cru.joined_at DESC ) res ) WHERE rnum BETWEEN #{startRow} AND #{endRow}

SELECT COUNT(*)
